const money = (value: number, digits = 0) => formatCurrencyValue(Number.isFinite(value) ? value : 0, { maximumFractionDigits: digits });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function paymentForMonths(balance: number, apr: number, months: number) {
  const r = apr / 100 / 12;
  if (r === 0) return balance / Math.max(1, months);
  return balance * r / (1 - Math.pow(1 + r, -months));
}

function payoff(balance: number, apr: number, payment: number) {
  let remaining = Math.max(0, balance);
  let totalInterest = 0;
  const monthlyRate = apr / 100 / 12;
  const schedule: { month: number; payment: number; principal: number; interest: number; balance: number }[] = [];
  for (let month = 1; month <= 1200 && remaining > 0.01; month++) {
    const interest = remaining * monthlyRate;
    if (payment <= interest) return { months: Infinity, totalInterest: Infinity, totalPaid: Infinity, schedule };
    const paid = Math.min(payment, remaining + interest);
    const principal = paid - interest;
    remaining = Math.max(0, remaining - principal);
    totalInterest += interest;
    schedule.push({ month, payment: paid, principal, interest, balance: remaining });
  }
  return { months: schedule.length, totalInterest, totalPaid: balance + totalInterest, schedule };
}

function monthsUntil(dateValue: string) {
  const target = new Date(dateValue);
  const now = new Date();
  if (Number.isNaN(target.getTime()) || target <= now) return 12;
  return Math.max(1, Math.ceil((target.getFullYear() - now.getFullYear()) * 12 + target.getMonth() - now.getMonth()));
}

