          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Month by Month Payoff Schedule</caption><thead className="bg-muted/60"><tr>{["Month", "Payment", "Principal", "Interest", "Balance"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.schedule.slice(0, 180).map((row) => <tr key={row.month}><td className="py-2.5 px-3">{row.month}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{money(row.principal)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
